def widths(*ratios):
    total = float(sum(ratios))
    return [(TEXT_WIDTH * r) / total for r in ratios]

def txt(value):
    return escape(value).replace("\n", "<br/>")

def styles():
    s = getSampleStyleSheet()
    s.add(ParagraphStyle(name="Body", parent=s["BodyText"], fontName="Times-Roman", fontSize=11, leading=14, alignment=TA_JUSTIFY, spaceAfter=6))
    s.add(ParagraphStyle(name="CoverTitle", parent=s["Title"], fontName="Times-Bold", fontSize=24, leading=28, alignment=TA_CENTER, textColor=colors.HexColor("#1F4E79"), spaceAfter=14))
    s.add(ParagraphStyle(name="CoverSub", parent=s["Title"], fontName="Times-Italic", fontSize=14, leading=18, alignment=TA_CENTER, textColor=colors.HexColor("#444444"), spaceAfter=12))
    s.add(ParagraphStyle(name="CoverDetail", parent=s["BodyText"], fontName="Times-Roman", fontSize=11.5, leading=14, alignment=TA_CENTER, spaceAfter=4))
    s.add(ParagraphStyle(name="FrontHeading", parent=s["Heading1"], fontName="Times-Bold", fontSize=16, leading=18, textColor=colors.HexColor("#1F4E79"), spaceBefore=6, spaceAfter=8))
    s.add(ParagraphStyle(name="H1", parent=s["Heading1"], fontName="Times-Bold", fontSize=16, leading=18, textColor=colors.HexColor("#1F4E79"), spaceBefore=10, spaceAfter=8))
    s.add(ParagraphStyle(name="H2", parent=s["Heading2"], fontName="Times-Bold", fontSize=13, leading=15, textColor=colors.HexColor("#2F5597"), spaceBefore=8, spaceAfter=6))
    s.add(ParagraphStyle(name="H3", parent=s["Heading3"], fontName="Times-Bold", fontSize=11.5, leading=13.5, textColor=colors.HexColor("#2F5597"), spaceBefore=6, spaceAfter=4))
    s.add(ParagraphStyle(name="FigCap", parent=s["BodyText"], fontName="Times-Bold", fontSize=10.5, leading=12, spaceBefore=6, spaceAfter=4))
    s.add(ParagraphStyle(name="TabCap", parent=s["BodyText"], fontName="Times-Bold", fontSize=10.5, leading=12, spaceBefore=8, spaceAfter=4))
    s.add(ParagraphStyle(name="FigHold", parent=s["BodyText"], fontName="Times-Italic", fontSize=10, leading=12, alignment=TA_CENTER, textColor=colors.HexColor("#555555")))
    s.add(ParagraphStyle(name="FigDesc", parent=s["BodyText"], fontName="Times-Roman", fontSize=9.5, leading=12, alignment=TA_LEFT, leftIndent=0.1 * inch, rightIndent=0.1 * inch, spaceAfter=8))
    s.add(ParagraphStyle(name="THead", parent=s["BodyText"], fontName="Times-Bold", fontSize=8.75, leading=10.75, textColor=colors.white, wordWrap="CJK"))
    s.add(ParagraphStyle(name="TCell", parent=s["BodyText"], fontName="Times-Roman", fontSize=8.5, leading=10.5, wordWrap="CJK"))
    s.add(ParagraphStyle(name="Ref", parent=s["BodyText"], fontName="Times-Roman", fontSize=10.5, leading=13, leftIndent=0.18 * inch, firstLineIndent=-0.18 * inch, spaceAfter=4))
    s.add(ParagraphStyle(name="CodeBlock", parent=s["Code"], fontName="Courier", fontSize=8.8, leading=10.5, leftIndent=0.15 * inch, rightIndent=0.15 * inch, backColor=colors.HexColor("#F6F6F6"), borderColor=colors.HexColor("#CCCCCC"), borderWidth=0.5, borderPadding=6, spaceAfter=8))
    return s

class Doc(BaseDocTemplate):
    def __init__(self, filename):
        super().__init__(filename, pagesize=LETTER, leftMargin=LEFT_MARGIN, rightMargin=RIGHT_MARGIN, topMargin=TOP_MARGIN, bottomMargin=BOTTOM_MARGIN, title="Site 2 Technical Report V6.0", author="Raspberry Pioneers")
        frame = Frame(self.leftMargin, self.bottomMargin, self.width, self.height, id="main")
        self.addPageTemplates([PageTemplate(id="main", frames=[frame], onPage=self.footer)])
    def footer(self, canvas, doc):
        canvas.saveState()
        canvas.setStrokeColor(colors.HexColor("#B0B0B0"))
        canvas.line(doc.leftMargin, 0.55 * inch, PAGE_WIDTH - doc.rightMargin, 0.55 * inch)
        canvas.setFont("Times-Roman", 9)
        canvas.setFillColor(colors.HexColor("#444444"))
        canvas.drawString(doc.leftMargin, 0.36 * inch, "Raspberry Pioneers | Site 2 Technical Report V6.0")
        canvas.drawRightString(PAGE_WIDTH - doc.rightMargin, 0.36 * inch, f"Page {canvas.getPageNumber()}")
        canvas.restoreState()
    def afterFlowable(self, flowable):
        if not isinstance(flowable, Paragraph):
            return
        name = flowable.style.name
        text = flowable.getPlainText()
        if name == "H1":
            self.notify("TOCEntry", (0, text, self.page))
        elif name == "H2":
            self.notify("TOCEntry", (1, text, self.page))
        elif name == "H3":
            self.notify("TOCEntry", (2, text, self.page))
        elif name == "FigCap":
            self.notify("TOCFigure", (0, text, self.page))
        elif name == "TabCap":
            self.notify("TOCTable", (0, text, self.page))

def add_heading(story, s, level, text):
    style = {1: "H1", 2: "H2", 3: "H3"}[level]
    story.append(Paragraph(txt(text), s[style]))

def add_para(story, s, text):
    story.append(Paragraph(txt(text), s["Body"]))

def make_figure_image(path, max_width=TEXT_WIDTH, max_height=8.0 * inch):
    width_px, height_px = ImageReader(str(path)).getSize()
    draw_width = max_width
    draw_height = draw_width * height_px / width_px
    if draw_height > max_height:
        draw_height = max_height
        draw_width = draw_height * width_px / height_px
    image = RLImage(str(path), width=draw_width, height=draw_height)
    image.hAlign = "CENTER"
    return image

def add_figure(story, s, label, caption, description):
    story.append(Paragraph(txt(f"{label}. {caption}"), s["FigCap"]))
    image_path = FIGURE_IMAGE_MAP.get(label)
    if image_path and image_path.exists():
        story.append(make_figure_image(image_path))
        story.append(Spacer(1, 0.08 * inch))
        return
    box = Table([[Paragraph(txt(f"[FIGURE PLACEHOLDER - {label}: {caption}]"), s["FigHold"])]], colWidths=[TEXT_WIDTH], rowHeights=[0.85 * inch])
    box.setStyle(TableStyle([("BOX", (0, 0), (-1, -1), 0.8, colors.HexColor("#888888")), ("BACKGROUND", (0, 0), (-1, -1), colors.HexColor("#F3F3F3")), ("VALIGN", (0, 0), (-1, -1), "MIDDLE")]))
    desc = Paragraph(txt(f"Description: {description}"), s["FigDesc"])
    story.append(KeepTogether([box, Spacer(1, 0.05 * inch), desc]))

def add_table(story, s, caption, headers, rows, col_widths):
    story.append(Paragraph(txt(caption), s["TabCap"]))
    data = [[Paragraph(txt(h), s["THead"]) for h in headers]]
    for row in rows:
        data.append([Paragraph(txt(str(cell)), s["TCell"]) for cell in row])
    table = LongTable(data, repeatRows=1, colWidths=col_widths)
    table.setStyle(TableStyle([("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1F4E79")), ("TEXTCOLOR", (0, 0), (-1, 0), colors.white), ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#888888")), ("VALIGN", (0, 0), (-1, -1), "TOP"), ("LEFTPADDING", (0, 0), (-1, -1), 4), ("RIGHTPADDING", (0, 0), (-1, -1), 4), ("TOPPADDING", (0, 0), (-1, -1), 4), ("BOTTOMPADDING", (0, 0), (-1, -1), 4), ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#F7F9FC")])]))
    story.append(table)
    story.append(Spacer(1, 0.1 * inch))

