        ParagraphStyle(name="TOC1", fontName="Times-Roman", fontSize=10.5, leading=12, spaceBefore=2),
        ParagraphStyle(name="TOC2", fontName="Times-Roman", fontSize=10, leading=11.5, leftIndent=0.22 * inch, spaceBefore=1),
